head.b:template-skin:

body#layout { background: #f1f5f9 !important; padding: 20px !important; }
body#layout .section h4 { display: none !important; }
body#layout #content-wrapper { display: flex !important; gap: 20px; max-width: 1200px; margin: 0 auto; }
body#layout #main-container { flex: 0 0 70%; }
body#layout #sidebar-container { flex: 0 0 28%; }
body#layout .footer-inner { display: flex !important; flex-wrap: nowrap !important; gap: 10px; }
body#layout .footer-col { flex: 1; border: 1px dashed #ccc; padding: 10px; }

head.b:skin:
/* <Group description="Theme Colors" title="Warna">
  <Variable name="primary.color" description="Primary" type="color" default="#ec4899" value="#2506d4"/>
  <Variable name="secondary.color" description="Secondary" type="color" default="#06b6d4" value="#F4A900"/>
</Group> */

:root {
  --primary: $(primary.color); --secondary: $(secondary.color);
  --bg: #ffffff; --surface: #f8fafc; --text: #0f172a; --border: #e2e8f0; --radius: 12px;
}
body.dark-mode { --bg: #0f172a; --surface: #1e293b; --text: #f8fafc; --border: #334155; }

* { margin:0; padding:0; box-sizing:border-box; }
body { font-family: 'Inter', sans-serif; background: var(--bg); color: var(--text); overflow-x: hidden; transition: 0.3s; }
.container { width:100%; max-width:1200px; margin:0 auto; padding:0 15px; }

/* [HEADER] */
header { background: linear-gradient(135deg, var(--primary), var(--secondary)); color: white; padding: 12px 0; position: sticky; top: 0; z-index: 9999; box-shadow: 0 4px 10px rgba(0,0,0,0.1); }
.header-inner { display: flex; align-items: center; justify-content: space-between; }
.logo h1 { font-size: 1.4rem; font-weight: 800; }
.logo a { color: white; text-decoration: none; }

/* [NAVIGASI DESKTOP] */
nav#main-nav ul { display: flex; list-style: none; gap: 1.2rem; }
nav#main-nav a { color: white; font-weight: 600; font-size: 0.85rem; text-decoration: none; text-transform: uppercase; }

/* [MEGA MENU] */
.has-mega { position: relative; }
.mega {
  position: absolute; top: 100%; left: 50%; transform: translateX(-50%) translateY(10px);
  background: var(--surface); padding: 1.5rem; border-radius: 12px; box-shadow: 0 10px 30px rgba(0,0,0,0.15);
  min-width: 450px; display: none; grid-template-columns: repeat(2, 1fr); gap: 1.5rem;
  opacity: 0; visibility: hidden; transition: 0.3s; border: 1px solid var(--border); z-index: 10000;
}
.has-mega:hover > .mega { display: grid !important; opacity: 1; visibility: visible; transform: translateX(-50%) translateY(0); }

/* [TICKER & SEARCH] */
.ticker-container { display: flex; align-items: center; background: var(--surface); border: 1px solid var(--border); border-radius: 10px; margin-top: 15px; height: 38px; overflow: hidden; }
.ticker-label { background: var(--primary); color: #fff; padding: 0 12px; height: 100%; display: flex; align-items: center; font-size: 10px; font-weight: 800; }
.search-dropdown { position: absolute; top: 100%; right: 0; width: 280px; background: var(--surface); padding: 10px; border-radius: 10px; display: none; z-index: 10001; margin-top: 8px; border: 1px solid var(--border); }
.search-dropdown.active { display: block !important; }

/* [FIX MOBILE MENU] */
#btnOpenMenu { display: none; background: none; border: none; color: white; cursor: pointer; }

@media (max-width: 850px) {
  #btnOpenMenu { display: block; }
  /* Menu di HP berubah jadi Drawer (Slide Samping) */
  nav#main-nav {
    position: fixed; top: 0; left: -100%; width: 280px; height: 100%;
    background: var(--surface); z-index: 10002; transition: 0.3s;
    padding: 30px 20px; box-shadow: 10px 0 30px rgba(0,0,0,0.2);
  }
  nav#main-nav.active { left: 0; }
  nav#main-nav ul { flex-direction: column; gap: 15px; }
  nav#main-nav a { color: var(--text); font-size: 1rem; }
  .mega { position: static !important; display: none !important; opacity: 1 !important; visibility: visible !important; transform: none !important; min-width: 100% !important; padding: 10px 0 0 15px !important; box-shadow: none !important; border: none !important; }
  .has-mega:hover .mega { display: block !important; }

  /* Grid 1 Kolom HP */
  .posts-grid { grid-template-columns: 1fr !important; }
  #sidebar-container { display: none !important; }
}

/* [POST GRID] */
#content-wrapper { display: flex; flex-wrap: wrap; gap: 25px; margin-top: 25px; }
#main-container { flex: 1; min-width: 0; }
#sidebar-container { width: 300px; flex-shrink: 0; }
.posts-grid { display: grid; grid-template-columns: repeat(2, 1fr); gap: 20px; }
.post-card { background: var(--surface); border-radius: 12px; border: 1px solid var(--border); overflow: hidden; }
.thumbnail img { width: 100%; aspect-ratio: 16/9; object-fit: cover; display: block; }
/* [FOOTER FRAME & CENTER ALIGNMENT] */
footer {
  background: #020617;
  color: #f1f5f9;
  padding: 50px 0 20px;
  margin-top: 50px;
  border-top: 4px solid var(--primary);
}

.footer-inner {
  display: grid;
  grid-template-columns: repeat(4, 1fr); /* 4 Kolom sejajar */
  gap: 20px;
  width: 100%;
}

.footer-col {
  /* Membuat Frame */
  border: 2px solid var(--primary); /* Garis warna sesuai tema utama */
  border-radius: 15px;
  padding: 25px 15px;
  background: rgba(255, 255, 255, 0.03); /* Background tipis di dalam frame */

  /* Posisi Konten Center */
  display: flex;
  flex-direction: column;
  align-items: center; /* Center horizontal */
  justify-content: flex-start;
  text-align: center; /* Center teks */
  transition: all 0.3s ease;
}

.footer-col:hover {
  border-color: var(--secondary); /* Warna garis berubah saat di-hover */
  transform: translateY(-5px);
  background: rgba(255, 255, 255, 0.05);
}

/* Merapikan Widget di Dalam Footer */
.footer-col .widget {
  width: 100%;
  margin-bottom: 15px;
}

.footer-col h2, 
.footer-col h3, 
.footer-col .title {
  font-size: 14px;
  font-weight: 800;
  text-transform: uppercase;
  margin-bottom: 15px;
  color: var(--primary);
  display: block;
}

.footer-col ul {
  list-style: none;
  padding: 0;
  margin: 0;
  width: 100%;
}

.footer-col ul li {
  margin-bottom: 8px;
}

.footer-col a {
  color: #cbd5e1;
  text-decoration: none;
  font-size: 13px;
}

.footer-col a:hover {
  color: var(--secondary);
}

/* Responsif Mobile */
@media (max-width: 900px) {
  .footer-inner {
    grid-template-columns: repeat(2, 1fr); /* 2 Kolom di Tablet */
  }
}

@media (max-width: 500px) {
  .footer-inner {
    grid-template-columns: 1fr; /* 1 Kolom di HP */
    padding: 0 10px;
  }
}

b:includable.script:
    (function() {
      var items = ;
      var msgs = ;
      var config = ;

// 
      var cursor = null;
      if (items && items.length > 0) {
        cursor = parseInt(items[items.length - 1].timestamp) + 1;
      }

      var bodyFromEntry = function(entry) {
        var text = (entry &&
                    ((entry.content && entry.content.$t) ||
                     (entry.summary && entry.summary.$t))) ||
            '';
        if (entry && entry.gd$extendedProperty) {
          for (var k in entry.gd$extendedProperty) {
            if (entry.gd$extendedProperty[k].name == 'blogger.contentRemoved') {
              return '<span class="deleted-comment">' + text + '</span>';
            }
          }
        }
        return text;
      }

      var parse = function(data) {
        cursor = null;
        var comments = [];
        if (data && data.feed && data.feed.entry) {
          for (var i = 0, entry; entry = data.feed.entry[i]; i++) {
            var comment = {};
            // comment ID, parsed out of the original id format
            var id = /blog-(\d+).post-(\d+)/.exec(entry.id.$t);
            comment.id = id ? id[2] : null;
            comment.body = bodyFromEntry(entry);
            comment.timestamp = Date.parse(entry.published.$t) + '';
            if (entry.author && entry.author.constructor === Array) {
              var auth = entry.author[0];
              if (auth) {
                comment.author = {
                  name: (auth.name ? auth.name.$t : undefined),
                  profileUrl: (auth.uri ? auth.uri.$t : undefined),
                  avatarUrl: (auth.gd$image ? auth.gd$image.src : undefined)
                };
              }
            }
            if (entry.link) {
              if (entry.link[2]) {
                comment.link = comment.permalink = entry.link[2].href;
              }
              if (entry.link[3]) {
                var pid = /.*comments\/default\/(\d+)\?.*/.exec(entry.link[3].href);
                if (pid && pid[1]) {
                  comment.parentId = pid[1];
                }
              }
            }
            comment.deleteclass = 'item-control blog-admin';
            if (entry.gd$extendedProperty) {
              for (var k in entry.gd$extendedProperty) {
                if (entry.gd$extendedProperty[k].name == 'blogger.itemClass') {
                  comment.deleteclass += ' ' + entry.gd$extendedProperty[k].value;
                } else if (entry.gd$extendedProperty[k].name == 'blogger.displayTime') {
                  comment.displayTime = entry.gd$extendedProperty[k].value;
                }
              }
            }
            comments.push(comment);
          }
        }
        return comments;
      };

      var paginator = function(callback) {
        if (hasMore()) {
          var url = config.feed + '?alt=json&v=2&orderby=published&reverse=false&max-results=50';
          if (cursor) {
            url += '&published-min=' + new Date(cursor).toISOString();
          }
          window.bloggercomments = function(data) {
            var parsed = parse(data);
            cursor = parsed.length < 50 ? null
                : parseInt(parsed[parsed.length - 1].timestamp) + 1
            callback(parsed);
            window.bloggercomments = null;
          }
          url += '&callback=bloggercomments';
          var script = document.createElement('script');
          script.type = 'text/javascript';
          script.src = url;
          document.getElementsByTagName('head')[0].appendChild(script);
        }
      };
      var hasMore = function() {
        return !!cursor;
      };
      var getMeta = function(key, comment) {
        if ('iswriter' == key) {
          var matches = !!comment.author
              && comment.author.name == config.authorName
              && comment.author.profileUrl == config.authorUrl;
          return matches ? 'true' : '';
        } else if ('deletelink' == key) {
          return config.baseUri + '/comment/delete/'
               + config.blogId + '/' + comment.id;
        } else if ('deleteclass' == key) {
          return comment.deleteclass;
        }
        return '';
      };

      var replybox = null;
      var replyUrlParts = null;
      var replyParent = undefined;

      var onReply = function(commentId, domId) {
        if (replybox == null) {
          // lazily cache replybox, and adjust to suit this style:
          replybox = document.getElementById('comment-editor');
          if (replybox != null) {
            replybox.height = '250px';
            replybox.style.display = 'block';
            replyUrlParts = replybox.src.split('#');
          }
        }
        if (replybox && (commentId !== replyParent)) {
          replybox.src = '';
          document.getElementById(domId).insertBefore(replybox, null);
          replybox.src = replyUrlParts[0]
              + (commentId ? '&parentID=' + commentId : '')
              + '#' + replyUrlParts[1];
          replyParent = commentId;
        }
      };

      var hash = (window.location.hash || '#').substring(1);
      var startThread, targetComment;
      if (/^comment-form_/.test(hash)) {
        startThread = hash.substring('comment-form_'.length);
      } else if (/^c[0-9]+$/.test(hash)) {
        targetComment = hash.substring(1);
      }

      // Configure commenting API:
      var configJso = {
        'maxDepth': config.maxThreadDepth
      };
      var provider = {
        'id': config.postId,
        'data': items,
        'loadNext': paginator,
        'hasMore': hasMore,
        'getMeta': getMeta,
        'onReply': onReply,
        'rendered': true,
        'initComment': targetComment,
        'initReplyThread': startThread,
        'config': configJso,
        'messages': msgs
      };

      var render = function() {
        if (window.goog && window.goog.comments) {
          var holder = document.getElementById('comment-holder');
          window.goog.comments.render(holder, provider);
        }
      };

      // render now, or queue to render when library loads:
      if (window.goog && window.goog.comments) {
        render();
      } else {
        window.goog = window.goog || {};
        window.goog.comments = window.goog.comments || {};
        window.goog.comments.loadQueue = window.goog.comments.loadQueue || [];
        window.goog.comments.loadQueue.push(render);
      }
    })();
//

body.script:
//
(function() {
  /* Auto Year */
  document.getElementById('y-copy').textContent = new Date().getFullYear();

  /* Hamburger Menu Toggle */
  const btnMenu = document.getElementById('btnOpenMenu');
  const mainNav = document.getElementById('main-nav');
  if (btnMenu) {
    btnMenu.onclick = (e) => {
      e.stopPropagation();
      mainNav.classList.toggle('active');
    };
    document.addEventListener('click', () => mainNav.classList.remove('active'));
    mainNav.onclick = (e) => e.stopPropagation();
  }

  /* Slider Auto-Play */
  const slider = document.getElementById('sliderWrapper');
  if (slider) {
    setInterval(() => {
      const max = slider.scrollWidth - slider.clientWidth;
      if (slider.scrollLeft >= max - 5) slider.scrollTo({ left: 0, behavior: 'smooth' });
      else slider.scrollBy({ left: 260, behavior: 'smooth' });
    }, 5000);
  }

  /* Search & Dark Mode */
  const btnS = document.getElementById('btnOpenSearch');
  const dropS = document.getElementById('searchDrop');
  if (btnS) {
    btnS.onclick = (e) => { e.stopPropagation(); dropS.classList.toggle('active'); };
    document.addEventListener('click', () => dropS.classList.remove('active'));
    dropS.onclick = (e) => e.stopPropagation();
  }

  const btnT = document.getElementById('btnThemeToggle');
  if (btnT) {
    if (localStorage.getItem('theme') === 'dark') document.body.classList.add('dark-mode');
    btnT.onclick = () => {
      document.body.classList.toggle('dark-mode');
      localStorage.setItem('theme', document.body.classList.contains('dark-mode') ? 'dark' : 'light');
    };
  }
})();
//
